module RefModule(
    input clk,
    input reset,      // Synchronous active-high reset
    input up_down,    // Control signal to increment or decrement
    output [3:0] q);reg [3:0] obf_count;

    always @(posedge clk) begin
        if (reset) begin
            obf_count <= 4'b0;
        end else if (up_down) begin
            obf_count <= (obf_count == 4'b1111) ? 4'b0 : obf_count + 1;
        end else begin
            obf_count <= (obf_count == 4'b0000) ? 4'b1111 : obf_count - 1;
        end
    end

    assign q = obf_count;

endmodule
